    // Sample Users Data
    val usersData = Seq(
      (1, "Alice", "New York", "Premium"),
      (2, "Bob", "Los Angeles", "Standard"),
      (3, "Charlie", "New York", "Standard"),
      (4, "David", "Chicago", "Premium"),
      (5, "Eve", "Los Angeles", "Standard")
    )
    val usersDF = spark.createDataFrame(usersData).toDF("user_id", "name", "city", "membership_type")
    usersDF.createOrReplaceTempView("users")
    println("\n'users' table registered:")
