      (104, "Monitor", 300.00)
    )
    val productsDF = spark.createDataFrame(productsData).toDF("product_id", "product_name", "price")
    productsDF.createOrReplaceTempView("products")
    println("\n'products' table registered:")
    productsDF.show()

    // Sample Orders Data (linking users and products)
    val ordersData = Seq(
      (1, 101, 2, 2400.00),
      (1, 102, 1, 25.00),
      (2, 103, 1, 75.00),
      (3, 104, 3, 900.00),
      (4, 101, 1, 1200.00),
      (5, 102, 5, 125.00)
    )
    val ordersDF = spark.createDataFrame(ordersData).toDF("user_id", "product_id", "quantity", "total_amount")
    ordersDF.createOrReplaceTempView("orders")
    println("\n'orders' table registered:")
    ordersDF.show()

    println("\nData preparation complete. Ready to execute user queries.")

    // 3. Demonstrate with example user queries
    val userQueries = Seq(
