  /**
   * Executes a user-provided SQL query using SparkSession.
   * This function encapsulates the core logic of accepting and executing queries.
   *
   * @param spark The active SparkSession.
   * @param userQuery The SQL query string provided by the user.
   * @return A `Try[DataFrame]` representing the result of the query execution.
   *         `Success(DataFrame)` if the query was successful, `Failure(Throwable)` otherwise.
   */
  def executeUserQuery(spark: SparkSession, userQuery: String): Try[DataFrame] = {
    Try {
      // Execute the SQL query
      val resultDF = spark.sql(userQuery)

      // Force an action to catch potential execution errors early
      // For example, if a table or column does not exist,
      // .show() or .count() will trigger the error.
      // We'll return the DF here, and let the caller decide what action to take.
